parameters.jsCode:
const raw = $input.first().json;
const body = raw.body ?? raw;

const message =
  body.message ??
  body.text ??
  body.mensagem ??
  body.data?.message?.conversation ??
  body.data?.message?.extendedTextMessage?.text ??
  '';

let phone =
  body.phone ??
  body.from ??
  body.telefone ??
  body.data?.key?.remoteJid ??
  body.data?.Info?.Sender ??
  '';

phone = String(phone).replace('@s.whatsapp.net', '').replace(/\D/g, '');

const name = body.name ?? body.pushName ?? body.data?.pushName ?? 'Usuário';

if (!message) {
  throw new Error('Campo message/text não encontrado no payload do webhook.');
}

return [{
  json: {
    message: String(message).trim(),
    phone,
    sessionId: phone || 'intt-default',
    name: String(name).trim(),
  }
}];

